module top_module(
  reset_clk,
  rst,
  inc,
  index
);input reset_clk;
  input rst;
  input inc;

  output[2:0] index;

  reg[2:0] count;
  reg[2:0] next;
  always @* begin
    if (rst)
    	next = 3'b000;
    else if (count == 3'b111)
    	next = count;
    else if (inc)
      next = count + 3'b001;
  	else
      next = count;
  end


  always @(posedge reset_clk) begin
    count <= next;
  end

  assign index = count;
endmodule
